function syncConsent(){const c=consent();if(!c.participantId)return Promise.resolve();return postApi('/v1/consent',{participantId:c.participantId,consentVersion:c.version,anonymousAnalytics:c.anonymousAnalytics,anonymousTrainingFeedback:c.anonymousTrainingFeedback,cycleAggregate:c.cycleAggregate,updatedDate:today()})}
function syncTrainingFeedback(log,w,result){const c=consent();if(!c.anonymousTrainingFeedback||!c.participantId)return Promise.resolve();const payload={participantId:c.participantId,consentVersion:c.version,submittedDate:today(),completion:log.completion,afterFeeling:log.afterFeeling,recommendationAccuracy:log.recommendationAccuracy,dayType:result?.dayType||'',workoutType:w.typeLabel||w.type},phase=phaseForUpload(result);if(phase)payload.cyclePhase=phase;return postApi('/v1/training-feedback',payload)}
function syncProductFeedback(item){const c=consent();if(!item.shareText||!c.participantId)return Promise.resolve();return postApi('/v1/product-feedback',{participantId:c.participantId,consentVersion:c.version,submittedDate:today(),feedbackType:item.type,satisfaction:Number(item.satisfaction),text:item.text.trim(),textConsent:true})}
function deleteCloudData(){const c=consent();if(!apiReady())return tip('测试数据同步暂未启用，暂无云端数据可删除。');if(!c.participantId)return tip('当前设备还没有匿名测试编号。');if(!confirm('确认请求删除这个匿名编号已上传的测试数据吗？本机记录不会被删除。'))return;postApi('/v1/delete-my-data',{participantId:c.participantId}).then(()=>{saveConsentState({...consent(),cloudDeletionRequestedAt:now()});tip('已请求删除云端匿名测试数据。')}).catch(()=>syncTip())}
function tip(message){toastEl.textContent=message;toastEl.classList.add('visible');clearTimeout(tip.t);tip.t=setTimeout(()=>toastEl.classList.remove('visible'),2600);}
function menstruationDays(){return [...new Set(read(STORAGE_KEYS.MENSTRUATION_DAYS,[]).filter(x=>/^\d{4}-\d{2}-\d{2}$/.test(x)))].sort()}
function saveMenstruationDays(days){save(STORAGE_KEYS.MENSTRUATION_DAYS,[...new Set(days)].sort())}
function deriveEpisodes(days=menstruationDays()){const sorted=[...new Set(days)].sort(),episodes=[];for(const day of sorted){const last=episodes[episodes.length-1];if(last&&addDays(last.end_date,1)===day)last.end_date=day;else episodes.push({start_date:day,end_date:day})}return episodes}
function cycleModel(days=menstruationDays(),ref=today()){const episodes=deriveEpisodes(days),recent=episodes.slice(-3),starts=recent.map(x=>x.start_date),cycles=[];for(let i=1;i<starts.length;i++)cycles.push(daysBetween(starts[i-1],starts[i]));const avg=a=>Math.round(a.reduce((s,n)=>s+n,0)/a.length),cycleLength=cycles.length?avg(cycles):28,periods=recent.map(e=>daysBetween(e.start_date,e.end_date)+1).filter(Boolean),periodLength=periods.length?avg(periods):5,status=episodes.length<2?'building':episodes.length>=3?'stable':'predicting',lastStart=starts.at(-1)||null;if(!lastStart)return{episodes,recent,cycle_length_days:cycleLength,period_length_days:periodLength,cycle_day:null,current_phase:null,status,last_start_date:null,insufficient:true};const elapsed=daysBetween(lastStart,ref),cycleDay=((elapsed%cycleLength)+cycleLength)%cycleLength+1,mid=Math.round(cycleLength/2),currentPhase=cycleDay<=periodLength?'menstrual':Math.abs(cycleDay-mid)<=2?'ovulation':cycleDay<mid-2?'follicular':'luteal';return{episodes,recent,cycle_length_days:cycleLength,period_length_days:periodLength,cycle_day:cycleDay,current_phase:currentPhase,status,last_start_date:lastStart,insufficient:false}}
const PHASES={menstrual:{name:'月经期',label:'预计月经期',tone:'低能量 / 恢复期',color:'#e95a62',explanation:'你当前大致处于月经期。出血、疼痛、疲劳或想休息都很常见，今天的训练建议会更看重疼痛和精力。'},follicular:{name:'卵泡期',label:'预计卵泡期',tone:'精力上升 / 适合训练',color:'#4c8fd8',explanation:'你当前大致处于卵泡期。很多人在这个阶段精力和训练状态更稳定，但仍要结合睡眠、压力和疼痛判断。'},ovulation:{name:'排卵期',label:'预计排卵期',tone:'力量峰值 / 表现最佳',color:'#53b86a',explanation:'你当前可能接近排卵期。状态好时可以正常训练；若有关节不适或疲劳，建议加强热身和动作控制。'},luteal:{name:'黄体期',label:'预计黄体期',tone:'疲劳 / 水肿 / 情绪波动',color:'#f0c34e',explanation:'你当前大致处于黄体期。部分人会感觉恢复变慢、疲劳、水肿或情绪波动；训练目标可以从突破改为维持。'}};
const PHASE_HOTSPOTS={menstrual:'M 144 247 C 96 230 63 185 61 132 C 84 137 106 141 130 145 C 129 171 140 194 160 211 C 155 222 150 234 144 247 Z',follicular:'M 61 132 C 66 79 104 35 157 21 C 164 43 171 65 179 88 C 156 100 139 120 130 145 C 106 141 84 137 61 132 Z',ovulation:'M 157 21 C 212 9 269 27 305 69 C 287 83 270 99 254 116 C 234 95 208 84 179 88 C 171 65 164 43 157 21 Z',luteal:'M 305 69 C 343 115 349 184 316 235 C 281 286 214 307 144 247 C 150 234 155 222 160 211 C 182 229 212 238 241 230 C 271 222 294 200 304 170 C 311 151 311 132 304 114 C 298 99 290 84 305 69 Z'};
function estimateCyclePhase(profile){
 const model=cycleModel();if(model.last_start_date){const meta=PHASES[model.current_phase],confidence=model.status==='stable'?'中高':model.status==='predicting'?'中':'低';return{cycleDay:model.cycle_day,phase:meta.name,phaseKey:model.current_phase,phaseLabel:meta.label,confidence,explanation:meta.explanation,cycleLength:model.cycle_length_days,periodLength:model.period_length_days,daysToNext:model.cycle_length_days-model.cycle_day,modelStatus:model.status,current_phase:model.current_phase,episodes:model.episodes}}
 const supplied=Array.isArray(profile?.periodStartDates)?profile.periodStartDates:String(profile?.periodStartDates||'').split(/[\n,，\s]+/).filter(Boolean);const dates=supplied.filter(x=>/^\d{4}-\d{2}-\d{2}$/.test(x)).sort();let cycle=Number(profile?.averageCycleLength)||28;
 if(dates.length>=2){const gaps=dates.slice(1).map((x,i)=>Math.round((new Date(`${x}T12:00:00`)-new Date(`${dates[i]}T12:00:00`))/86400000)).filter(x=>x>=18&&x<=60);if(gaps.length)cycle=Math.round(gaps.reduce((a,b)=>a+b,0)/gaps.length)}
 const period=Number(profile?.averagePeriodLength)||5,start=profile?.lastPeriodStartDate||dates.at(-1);
 const unknown={cycleDay:null,phase:'不确定',phaseLabel:'周期阶段暂不确定',confidence:'低',explanation:'目前周期信息不足或波动较大，我们不会强行判断激素阶段。今天将主要根据睡眠、精力、疼痛和训练意愿给出建议。',cycleLength:cycle,periodLength:period};
 if(!start||['很不规律','不确定'].includes(profile?.periodRegularity))return unknown;const elapsed=Math.floor((new Date(`${today()}T12:00:00`)-new Date(`${start}T12:00:00`))/86400000);if(!Number.isFinite(elapsed)||elapsed<0)return unknown;
 const cycleDay=elapsed%cycle+1,ovu=Math.max(period+2,cycle-14),toNext=cycle-cycleDay,confidence=dates.length>=2&&profile.periodRegularity==='比较规律'?'中高':'中';let phase='黄体期',phaseLabel='预计黄体期',explanation='你当前大致处于黄体期。部分人会感觉恢复变慢、疲劳或情绪波动；今天仍以睡眠、压力和疼痛作为训练强度的主要依据。';
 if(cycleDay<=period){phase='月经期';phaseLabel='预计月经期';explanation='你当前大致处于月经期。出血、疼痛、疲劳或想休息都很常见，今天的训练建议会更看重疼痛和精力。'}
 else if(cycleDay<ovu-2){phase='卵泡期';phaseLabel='预计卵泡期（低激素期）';explanation='你当前大致处于卵泡期。很多人在这个阶段精力和训练状态更稳定，但仍要结合睡眠、压力和疼痛判断。'}
 else if(cycleDay<=ovu+2){phase='排卵窗口';phaseLabel='预计接近排卵窗口';explanation='你当前可能接近排卵窗口。状态好时可以正常训练；若有关节不适或疲劳，建议加强热身和动作控制。'}
 else if(toNext>=0&&toNext<=5){phase='经前期';phaseLabel='预计经前期';explanation='你当前可能接近经前期。疲劳、睡眠变差、情绪波动、腹胀或食欲变化都可能出现；训练目标可以从突破改为维持或恢复。'}
 return{cycleDay,phase,phaseLabel,confidence,explanation,cycleLength:cycle,periodLength:period,daysToNext:toNext};
}
function calculateRecommendation(c,profile={}){let score=5;const p={sleep:{'好':2,'一般':0,'差':-2},energy:{'高':2,'中':0,'低':-2},pain:{'无':1,'轻微':-1,'明显':-3},soreness:{'无':1,'轻微':-1,'明显':-3},stressMood:{'稳定':1,'有点压力':-1,'压力很大 / 情绪波动明显':-2},cycleStatus:{'非经期，状态稳定':1,'经期第 1—2 天':-2,'经期第 3 天及以后':-1,'经前疲劳 / PMS 明显':-2,'周期不规律 / 不确定':0,'不适用':0},trainingIntent:{'很想练':2,'可以练':1,'不太想练':-1,'只想轻轻动一下':-2}};Object.entries(p).forEach(([k,v])=>score+=v[c[k]]||0);let dayType=score>=9?'冲刺日':score>=6?'常规日':score>=3?'降载日':'恢复日';
 if(c.pain==='明显')dayType='恢复日';if(c.soreness==='明显'&&dayType==='冲刺日')dayType='降载日';if(c.sleep==='差'&&c.energy==='低'&&['冲刺日','常规日'].includes(dayType))dayType='降载日';if(c.cycleStatus==='经期第 1—2 天'&&c.pain!=='无')dayType='恢复日';if(c.cycleStatus==='经前疲劳 / PMS 明显'&&c.stressMood==='压力很大 / 情绪波动明显'&&['冲刺日','常规日'].includes(dayType))dayType='降载日';if(c.cycleStatus==='经前疲劳 / PMS 明显'&&c.pain!=='明显'&&c.trainingIntent!=='只想轻轻动一下'&&dayType==='恢复日')dayType='降载日';const phase=estimateCyclePhase(profile);if(phase.phase==='经前期'&&c.sleep==='差'&&['冲刺日','常规日'].includes(dayType))dayType='降载日';return{score,dayType,copy:copy[dayType],phase};
}
function chooseWorkouts(profile,result){const goals=profile.goals||[],place=profile.trainingPlace||'都可以',isRegular=regular(profile),isBeginner=beginner(profile),phase=result.phase?.current_phase||result.phase?.phaseKey,allowedTypes=place.includes('健身房')||place.includes('都可以')?['machine','cable','dumbbell','barbell','bodyweight','mobility','pilates_yoga','hiit']:place.includes('自由重量')?['dumbbell','barbell','bodyweight','mobility','pilates_yoga','hiit']:place.includes('小器械')?['dumbbell','bodyweight','mobility','pilates_yoga','hiit']:['bodyweight','mobility','pilates_yoga','hiit'];let allowedIntensity=result.dayType==='恢复日'?['low']:result.dayType==='降载日'||phase==='luteal'||phase==='menstrual'?['low','medium']:['low','medium','high'];if(isBeginner)allowedIntensity=allowedIntensity.filter(x=>x!=='high');let pool=workoutLibraryV2.filter(w=>allowedTypes.includes(w.type)&&allowedIntensity.includes(w.intensity_level));if(goals.includes('减脂')&&result.dayType!=='恢复日')pool.sort((a,b)=>(b.type==='hiit')-(a.type==='hiit'));else if(isRegular&&['follicular','ovulation'].includes(phase)&&result.dayType!=='降载日')pool.sort((a,b)=>(['barbell','machine','dumbbell','cable'].includes(b.type))-(['barbell','machine','dumbbell','cable'].includes(a.type))||b.minutes-a.minutes);else if(result.dayType==='恢复日'||phase==='menstrual')pool.sort((a,b)=>(['mobility','pilates_yoga'].includes(b.type))-(['mobility','pilates_yoga'].includes(a.type)));if(!pool.length)pool=workoutLibraryV2.filter(w=>['mobility','bodyweight','pilates_yoga'].includes(w.type)&&allowedIntensity.includes(w.intensity_level));const picked=[];for(const w of pool){if(!picked.some(x=>x.type===w.type||x.id===w.id))picked.push(w);if(picked.length>=3)break}return picked.length?picked:workoutLibraryV2.slice(0,3)}
function reasons(profile,c,result){const r=[];if(c.sleep==='差'||c.energy==='低')r.push('睡眠和精力让今天的恢复空间变小');if(c.pain!=='无'||c.soreness==='明显')r.push('身体不适需要优先被照顾');if(c.cycleStatus.includes('经期')||c.cycleStatus.includes('经前'))r.push('你填写的周期状态也提示今天更适合灵活调整');if(result.phase.phase!=='不确定')r.push(`${result.phase.phaseLabel.replace('预计','')}只是额外的训练参考，不替代你的实际感受`);const level=profile.trainingLevel?`你的训练水平是「${profile.trainingLevel}」`:'';const goal=(profile.goals||[]).slice(0,2).join('、');return `${level}${level&&goal?'，':''}${goal?`你想关注${goal}`:''}。${r.length?r.join('；'):'今天的状态整体稳定，可以在动作质量优先的前提下完成训练。'}`}
function latest(){const a=newest(read(STORAGE_KEYS.DAILY_CHECKINS,[]),'date'),c=a.find(x=>x.date===today())||a[0];if(!c)return null;const p=read(STORAGE_KEYS.USER_PROFILE,{}),r=calculateRecommendation(c,p);return{...r,score:c.score??r.score,dayType:c.dayType||r.dayType,workouts:chooseWorkouts(p,r),checkin:c}}
const header=back=>`<header class="topbar"><div class="brand"><span class="brand-mark">力</span>女训 <span class="version-pill">0.2</span></div>${back?`<button class="icon-button" data-action="${back}" aria-label="返回">←</button>`:'<span class="top-spacer"></span>'}</header>`;
function nav(){const active=state.screen,item=(s,i,l)=>`<button class="nav-item ${active===s||(s==='library'&&active==='action')||(s==='result'&&['workout','feedback'].includes(active))?'active':''}" data-action="nav" data-screen="${s}"><b>${i}</b>${l}</button>`;return `<nav class="bottom-nav bottom-nav-six">${item('checkin','◉','今日')}${item('cycle','●','周期')}${item('library','▧','训练库')}${item('videos','▷','视频')}${item('records','▤','记录')}${item('privacy','□','隐私')}</nav>`}
