function captureProfile(form=document.querySelector('#profile-form')){if(!form)return;const e=form.elements;['lastPeriodStartDate','periodRegularity','averageCycleLength','averagePeriodLength'].forEach(k=>{if(e[k])state.profile[k]=e[k].value});if(e.periodStartDates)state.profile.periodStartDates=e.periodStartDates.value.split(/[\n,，\s]+/).filter(Boolean)}
