function welcome(){shell(`${header()}<section class="hero"><p class="eyebrow">TODAY, YOUR WAY</p><h1>长寿的女人，<em>任何时候</em>都可以开始训练。</h1><div class="hero-rule"></div><p>根据你的训练水平、月经周期、睡眠、精力与疼痛，判断今天适合怎么练。</p><button class="button button-primary" data-action="start">开始今日训练判断</button><button class="button button-quiet" data-action="go" data-screen="privacy">查看隐私说明</button></section><div class="privacy-strip"><strong>默认只在本机保存。</strong> 不登录、不上传、不接广告 SDK。周期判断仅供训练参考，你随时可以清除数据。</div>`,false)}
